mapper.select:
SELECT id, title, user_id as userId, model_id as modelId, model_name as modelName, prompt_template_id as promptTemplateId, message_count as messageCount, total_tokens as totalTokens, last_message_at as lastMessageAt, created_at as createdAt FROM chat_session WHERE is_deleted = 0 AND user_id = #{userId}
AND title LIKE CONCAT('%', #{keyword}, '%')
AND model_id = #{modelId}
ORDER BY last_message_at DESC, created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM chat_session
WHERE is_deleted = 0
  AND user_id = #{userId}

    AND title LIKE CONCAT('%', #{keyword}, '%')


    AND model_id = #{modelId}
